import{_ as t,b as e,G as i,a as n}from"./chunks/framework.BAghNNDe.js";const g=JSON.parse('{"title":"格林函数与费曼图","description":"","frontmatter":{"title":"格林函数与费曼图","date":"2025-04-19T00:00:00.000Z","tags":["many-body","Green function","Feynman diagram"],"excerpt":"格林函数把多体体系的激发、谱函数、响应函数和微扰展开放在同一个语言中；费曼图则是整理微扰级数的记账方式。"},"headers":[],"relativePath":"2025-04-19-格林函数与费曼图.md","filePath":"posts/2025-04-19-格林函数与费曼图/index.md"}'),s={name:"2025-04-19-格林函数与费曼图.md"};function p(r,a,d,o,h,l){return n(),e("div",null,a[0]||(a[0]=[i('<p>格林函数最容易让人困惑的地方在于：同一个词在数学物理、量子场论、凝聚态多体理论和数值计算里会有略微不同的记号。这里先把最常用的一套凝聚态多体记号整理出来，目标不是替代教材，而是给后面阅读 Dyson 方程、自能、Matsubara 频率和费曼图规则时提供一张地图。</p><h2 id="格林函数" tabindex="-1">格林函数 <a class="header-anchor" href="#格林函数" aria-label="Permalink to &quot;格林函数&quot;">​</a></h2><p>在二次量子化语言中，单粒子格林函数描述的是“在某个时空点加入一个粒子，体系怎样把这个扰动传播到另一个时空点”。把空间、自旋和时间统一写成 <span data-math>1=(\\mathbf r_1,\\sigma_1,t_1)</span>，零温时的时间有序格林函数通常定义为</p><div data-math>G(1,2)=-i\\langle \\Psi_0|T[\\hat\\psi_H(1)\\hat\\psi_H^\\dagger(2)]|\\Psi_0\\rangle . </div><p>这里 <span data-math>T</span> 是实时时间排序算符，<span data-math>\\hat\\psi_H</span> 是 Heisenberg 绘景中的场算符。这个对象同时包含两个过程：当 <span data-math>t_1&gt;t_2</span> 时，它像是在 <span data-math>2</span> 点加入一个粒子并传播到 <span data-math>1</span> 点；当 <span data-math>t_2&gt;t_1</span> 时，它等价于传播一个空穴。</p><h3 id="实时格林函数" tabindex="-1">实时格林函数 <a class="header-anchor" href="#实时格林函数" aria-label="Permalink to &quot;实时格林函数&quot;">​</a></h3><p>实时格林函数常见的几种分量是</p><div data-math>G^R(1,2)=-i\\theta(t_1-t_2)\\langle\\{\\hat\\psi_H(1),\\hat\\psi_H^\\dagger(2)\\}\\rangle , </div><div data-math>G^A(1,2)=i\\theta(t_2-t_1)\\langle\\{\\hat\\psi_H(1),\\hat\\psi_H^\\dagger(2)\\}\\rangle , </div><p>以及</p><div data-math>G^&gt;(1,2)=-i\\langle\\hat\\psi_H(1)\\hat\\psi_H^\\dagger(2)\\rangle,\\qquad G^&lt;(1,2)=i\\langle\\hat\\psi_H^\\dagger(2)\\hat\\psi_H(1)\\rangle . </div><p>其中 <span data-math>G^R</span> 是最直接对应线性响应和实验谱函数的对象。对平移不变体系，在频率动量空间中可以写成</p><div data-math>G^R(\\mathbf k,\\omega)=\\frac{1}{\\omega+\\mu-\\varepsilon_{\\mathbf k}-\\Sigma^R(\\mathbf k,\\omega)} . </div><p>这里 <span data-math>\\Sigma</span> 是自能。非相互作用体系中 <span data-math>\\Sigma=0</span>，格林函数的极点就是单粒子能级；有相互作用时，极点位置和宽度被自能修正，分别对应准粒子能量移动和寿命展宽。</p><p>实验上常用的谱函数为</p><div data-math>A(\\mathbf k,\\omega)=-\\frac{1}{\\pi}\\operatorname{Im}G^R(\\mathbf k,\\omega), </div><p>它和 ARPES、STM 等谱学实验中看到的强度有直接关系。严格地说，实验强度还会乘上矩阵元、费米分布以及仪器分辨函数，但谱函数是最核心的多体量。</p><h3 id="虚时格林函数" tabindex="-1">虚时格林函数 <a class="header-anchor" href="#虚时格林函数" aria-label="Permalink to &quot;虚时格林函数&quot;">​</a></h3><p>有限温多体理论更常用虚时 <span data-math>\\tau=it</span>。虚时单粒子格林函数定义为</p><div data-math>G(\\tau)=-\\langle T_\\tau \\hat c(\\tau)\\hat c^\\dagger(0)\\rangle,\\qquad 0\\le \\tau&lt;\\beta , </div><p>其中 <span data-math>\\beta=1/k_BT</span>。对费米子，格林函数满足反周期边界条件</p><div data-math>G(\\tau+\\beta)=-G(\\tau), </div><p>因此 Fourier 展开使用费米 Matsubara 频率</p><div data-math>i\\omega_n=i(2n+1)\\pi/\\beta . </div><p>对玻色子，频率则是</p><div data-math>i\\nu_n=i2n\\pi/\\beta . </div><p>虚时形式的好处是热平均和配分函数天然联系在一起，微扰展开中不会出现实时间轮廓上的振荡积分。代价是最后若要和真实谱函数比较，需要做解析延拓：</p><div data-math>i\\omega_n\\rightarrow \\omega+i0^+ . </div><p>这个步骤在数值上通常是病态的，因此量子 Monte Carlo 到实频谱函数的解析延拓会比公式看起来困难得多。</p><h3 id="dyson-方程" tabindex="-1">Dyson 方程 <a class="header-anchor" href="#dyson-方程" aria-label="Permalink to &quot;Dyson 方程&quot;">​</a></h3><p>微扰展开的核心结果可以浓缩为 Dyson 方程：</p><div data-math>G=G_0+G_0\\Sigma G . </div><p>在频率动量空间中，它等价于</p><div data-math>G^{-1}(\\mathbf k,\\omega)=G_0^{-1}(\\mathbf k,\\omega)-\\Sigma(\\mathbf k,\\omega). </div><p>这条式子说明我们不必把所有图都直接加到 <span data-math>G</span> 上，而是可以先整理出“单粒子不可约”的自能 <span data-math>\\Sigma</span>，再通过 Dyson 方程重求完整传播子。</p><h2 id="费曼图技术" tabindex="-1">费曼图技术 <a class="header-anchor" href="#费曼图技术" aria-label="Permalink to &quot;费曼图技术&quot;">​</a></h2><p>费曼图不是另一种物理假设，而是微扰级数的可视化记账方式。对一个相互作用哈密顿量</p><div data-math>\\hat H=\\hat H_0+\\hat V </div><p>我们以 <span data-math>\\hat H_0</span> 的格林函数作为裸传播子，把 <span data-math>\\hat V</span> 当作顶角展开。Wick 定理保证了非相互作用基态或热平衡态中的高阶关联函数可以分解为两两收缩，于是每一项都能画成线和顶角。</p><p>最基本的图像语言是：</p><ul><li>实线表示费米子传播子 <span data-math>G_0</span>。</li><li>波浪线或虚线常表示相互作用传播子，例如库仑相互作用 <span data-math>V(q)</span> 或声子传播子 <span data-math>D(q,\\omega)</span>。</li><li>顶角表示相互作用项，并伴随动量、频率守恒。</li><li>闭合费米子圈通常带来一个额外的负号。</li><li>拓扑相同的图要除以相应的对称因子。</li></ul><p>以电子-电子相互作用为例，最低阶自能包含 Hartree 项和 Fock 项。Hartree 项像平均场，描述一个电子感受到其他电子的平均电荷背景；Fock 项来自费米子交换反对称性，是 Hartree-Fock 理论中的交换能来源。</p><p>更高阶图会迅速增多，因此实际计算中通常要做选择：</p><ul><li>RPA：重点求和泡泡图，用于屏蔽相互作用。</li><li>GW：用格林函数 <span data-math>G</span> 和屏蔽库仑相互作用 <span data-math>W</span> 近似自能 <span data-math>\\Sigma=iGW</span>。</li><li>T-matrix：求和梯形图，适合处理散射和配对涨落。</li><li>Migdal-Eliashberg：在电子-声子问题中保留特定的自能修正。</li></ul><p>图形展开的一个重要原则是区分“连通图”和“不可约图”。连通图才对关联函数有贡献，而自能只保留切断一条单粒子线后仍不能分开的单粒子不可约图。这个分类是 Dyson 方程能够成立的图形基础。</p><h2 id="一个最小读图流程" tabindex="-1">一个最小读图流程 <a class="header-anchor" href="#一个最小读图流程" aria-label="Permalink to &quot;一个最小读图流程&quot;">​</a></h2><p>看到一张费曼图时，可以按以下顺序读：</p><ol><li>给每条内部线分配内部动量和 Matsubara 频率。</li><li>在每个顶角写下守恒条件。</li><li>写出所有传播子和相互作用线的乘积。</li><li>对内部变量求和或积分。</li><li>加上闭合费米子圈、顶角因子和对称因子。</li><li>判断它属于 <span data-math>G</span>、<span data-math>\\Sigma</span>、极化函数 <span data-math>\\Pi</span> 还是顶角函数 <span data-math>\\Gamma</span>。</li></ol><p>这比直接背图形规则可靠得多。图只是一种压缩表示，最后仍然要回到代数表达式。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p>第一，格林函数不是普通波函数。它是关联函数，包含多体基态或热平衡态的平均。</p><p>第二，虚时格林函数不是“虚假的时间演化”。它是有限温场论中处理配分函数和热平均的自然变量。</p><p>第三，费曼图不是只能用于相对论量子场论。凝聚态中的电子、声子、磁振子、Bogoliubov 准粒子都可以用类似图形语言处理。</p><p>第四，解析延拓不是把 <span data-math>i\\omega_n</span> 机械替换成 <span data-math>\\omega+i0^+</span> 就能数值完成。解析函数层面的关系很简单，有限噪声数据上的反问题很困难。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Piers Coleman, <a href="https://www.cambridge.org/core/services/aop-cambridge-core/content/view/8B7530A527D54CBE18EF2B481766E0AD/9781139020916c5_p95-126_CBO.pdf/greens-functions.pdf" target="_blank" rel="noreferrer">Green’s functions</a>, <em>Introduction to Many-Body Physics</em>.</li><li>Michael El-Batanouny, <a href="https://www.cambridge.org/core/books/advanced-quantum-condensed-matter-physics/green-functions-for-manybody-systems-and-feynman-diagrams/4C3AD7E9C0CEB3C80F434ECE8E83CD18" target="_blank" rel="noreferrer">Green Functions for Many-Body Systems and Feynman Diagrams</a>, <em>Advanced Quantum Condensed Matter Physics</em>.</li><li>Hiroshi Shinaoka et al., <a href="https://scipost.org/SciPostPhysLectNotes.63" target="_blank" rel="noreferrer">Efficient ab initio many-body calculations based on sparse modeling of Matsubara Green’s function</a>, <em>SciPost Physics Lecture Notes</em> 63 (2022).</li></ul>',56)]))}const c=t(s,[["render",p]]);export{g as __pageData,c as default};
